<script setup lang="ts">import{onMounted}from'vue';import{storeToRefs}from'pinia';import{useI18n}from'vue-i18n';import{clearMonitorHistory}from'@/api/diagnostics';import{useMonitorSocket}from'@/composables/useMonitorSocket';import{useMonitorStore}from'@/stores/monitor';import MonitorMetadata from'@/components/MonitorMetadata.vue';import MonitorOutput from'@/components/MonitorOutput.vue';import MonitorRequestList from'@/components/MonitorRequestList.vue';const{t}=useI18n(),store=useMonitorStore(),socket=useMonitorSocket();const{records,selectedId,selected,autoSelect}=storeToRefs(store);async function clear(){if(!confirm(t('monitor.clearConfirm')))return;await clearMonitorHistory();store.clear()}async function copy(text:string){await navigator.clipboard.writeText(text)}onMounted(socket.connect)</script><template><section class="page monitor-page"><header class="page-heading"><div><p class="eyebrow">{{t('monitor.eyebrow')}}</p><h1>{{t('monitor.title')}}</h1></div><div class="button-row"><span :class="`connection ${socket.state.value}`">{{t(`monitor.connection.${socket.state.value}`)}}</span><button @click="socket.reconnect">{{t('monitor.reconnect')}}</button><button @click="clear">{{t('monitor.clear')}}</button></div></header><label class="check"><input v-model="autoSelect" type="checkbox">{{t('monitor.autoSelect')}}</label><div class="monitor-layout"><MonitorRequestList :records="records" :selected-id="selectedId" @select="store.select"/><main v-if="selected"><MonitorMetadata :record="selected"/><p v-if="selected.error" class="error-text">{{selected.error}}</p><MonitorOutput :title="t('monitor.reasoning')" :text="selected.reasoning" :empty="t('monitor.noReasoning')" @copy="copy"/><MonitorOutput :title="t('monitor.content')" :text="selected.content" :empty="t('monitor.noContent')" @copy="copy"/></main><main v-else><p>{{t('monitor.emptyDetail')}}</p></main></div></section></template>
